cedar_template:
permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"check_availability",
  resource == Calendar::"primary"
) when {
  context.query_window_days <= {{days_ahead}}
};
forbid (
  principal == Agent::"{{audience_did}}",
  action,
  resource == Calendar::"primary"
) when {
  action != Action::"check_availability"
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"cancel_event",
  resource == Calendar::"primary"
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"create_event",
  resource == Calendar::"primary"
) when {
  context.events_created_today < {{max_per_day}}
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"modify_event",
  resource == Calendar::"primary"
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"propose_meeting",
  resource == Calendar::"primary"
) when {
  context.proposed_attendee_count <= {{max_attendees}} &&
  context.proposed_duration_min <= {{max_duration_min}}
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"read",
  resource == Calendar::"primary"
) when {
  context.query_window_days <= {{window_days}}
  {{#if include_private_flag}}
  {{else}}
  && !resource.tags.contains("private")
  {{/if}}
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"extend_connection",
  resource == Connection::"self"
) when {
  context.requested_extension_days <= {{days}}
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"request_rescope",
  resource == Connection::"self"
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"read",
  resource == Contact
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"request_contact_introduction",
  resource == Contact
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"search_contacts",
  resource == Contact
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"share_external",
  resource == Contact
) when {
  context.recipient_matches_allowlist({{recipient_allowlist_json}})
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"present_vc",
  resource == Credential
) when {
  resource.type in {{required_vcs_json}}
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"request_zk_proof",
  resource == Credential::"{{attribute}}"
) when {
  context.predicate == "{{predicate}}"
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"redelegate",
  resource == Connection::"self"
) when {
  context.delegate_target in {{agent_allowlist_json}} &&
  context.attenuation_mode == "{{scope_attenuation}}"
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"delete",
  resource in Project::"{{project_id}}"
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"list",
  resource in Project::"{{project_id}}"
);

permit (
  principal == Agent::"{{audience_did}}",
  action in [Action::"read", Action::"list"],
  resource in Project::"{{project_id}}"
) when {
  resource.size_bytes <= {{max_size_mb}} * 1048576 &&
  !resource.tags.contains("confidential") &&
  !resource.tags.contains("do-not-share")
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"summarize",
  resource in Project::"{{project_id}}"
);

permit (
  principal == Agent::"{{audience_did}}",
  action in [Action::"write", Action::"update"],
  resource in Project::"{{project_id}}"
) when {
  context.written_size_bytes <= {{max_size_mb}} * 1048576
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"read_metadata",
  resource == Project::"{{project_id}}"
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"list",
  resource == ProjectRegistry::"self"
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"share_external",
  resource in Project::"{{project_id}}"
) when {
  context.recipient_matches_allowlist({{recipient_allowlist_json}})
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"read",
  resource == AgentCard::"self"
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"request_introduction",
  resource == Agent::"{{to_agent}}"
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"verify_principal",
  resource == Principal::"self"
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"query",
  resource == KnowledgeBase::"{{kb_id}}"
) when {
  context.requested_tokens <= {{max_tokens}}
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"send_chat",
  resource == ChatChannel
) when {
  resource.id in {{channel_allowlist_json}}
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"compose_draft",
  resource == Email::"drafts"
);
forbid (
  principal == Agent::"{{audience_did}}",
  action == Action::"send_email",
  resource
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"send_email",
  resource == Email::"outbox"
) when {
  {{#if recipient_allowlist}}
  context.recipient_matches_allowlist({{recipient_allowlist_json}})
  {{else}}
  true
  {{/if}}
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"summarize",
  resource == Email
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"read",
  resource == Email
) {{#if label_filter}}when {
  resource.labels.containsAny({{label_filter_json}})
}{{/if}};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"relay_to_principal",
  resource == Principal::"self"
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"read",
  resource in Collection::"{{collection_id}}"
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"search",
  resource in Collection::"{{collection_id}}"
);

permit (
  principal == Agent::"{{audience_did}}",
  action in [Action::"write", Action::"update"],
  resource in Collection::"{{collection_id}}"
) when {
  context.notes_written_today < {{max_per_day}}
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"authorize_payment",
  resource == Wallet::"primary"
) when {
  context.quoted_price_usd <= {{max_per_txn_usd}} &&
  context.spend_last_30d_usd + context.quoted_price_usd <= {{max_per_30d_usd}}
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"read",
  resource == PaymentHistory::"self"
) when {
  context.query_window_days <= {{days_back}}
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"request_quote",
  resource == Wallet::"primary"
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"request_refund",
  resource == Payment
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"assign",
  resource in Project::"{{project_id}}"
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"create",
  resource in Project::"{{project_id}}"
) when {
  context.tasks_created_today < {{max_per_day}}
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"list",
  resource in Project::"{{project_id}}"
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"read",
  resource in Project::"{{project_id}}"
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"update_status",
  resource in Project::"{{project_id}}"
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"invoke_tool",
  resource == Tool
) when {
  resource.id in {{tool_allowlist_json}} &&
  context.requests_last_day <= {{max_per_day}}
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"invoke_tool",
  resource == Tool
) when {
  resource.id in {{tool_allowlist_json}} &&
  resource.readonly == true
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"list",
  resource == WorkProjects::"self"
);

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"summarize",
  resource == WorkReport::"self"
) when {
  context.period == "{{period}}"
};

permit (
  principal == Agent::"{{audience_did}}",
  action == Action::"read",
  resource == WorkStatus::"self"
);
